insert into service_pages (language, slug, title, summary, body, features, sort_order) values
('it','reti-informatiche','Reti informatiche','Infrastrutture affidabili per connettere sedi, persone e servizi.','Progettiamo, proteggiamo e manteniamo reti LAN/WAN, server, firewall, VPN, Wi-Fi aziendale e ambienti virtualizzati con assistenza sistemistica continuativa.','["Infrastrutture LAN/WAN","Server","Firewall","VPN","Wi-Fi aziendale","Virtualizzazione","Assistenza sistemistica"]',1),
('it','elettronica','Elettronica','Consulenza e supporto tecnico per dispositivi e componenti.','Affianchiamo aziende industriali nella scelta, diagnostica e integrazione di dispositivi elettronici, componentistica e soluzioni custom.','["Consulenza elettronica","Dispositivi industriali","Componentistica","Diagnostica","Supporto tecnico"]',2),
('it','sicurezza','Sicurezza','Protezione fisica e digitale per l azienda.','Integriamo videosorveglianza, controllo accessi, sistemi antifurto, cybersecurity, backup e protezione dati in un approccio coordinato.','["Videosorveglianza","Controllo accessi","Sistemi antifurto","Cybersecurity","Backup e protezione dati"]',3),
('it','automazione','Automazione','Sistemi intelligenti per processi piu efficienti.','Realizziamo automazione industriale, integrazione dispositivi, controllo processi e sistemi intelligenti collegati ai dati aziendali.','["Automazione industriale","Integrazione dispositivi","Controllo processi","Sistemi intelligenti"]',4),
('it','wms','WMS','Gestione magazzino tracciabile e integrata.','Implementiamo soluzioni WMS con terminali barcode, integrazione ERP, dashboard, report e ottimizzazione logistica.','["Gestione magazzino","Tracciabilita","Terminali barcode","Integrazione ERP","Ottimizzazione logistica","Dashboard e report"]',5),
('it','energia-green','Energia green','Tecnologie sostenibili per produrre e monitorare energia.','Supportiamo progetti fotovoltaici con batterie, inverter, monitoraggio consumi e soluzioni energetiche sostenibili.','["Fotovoltaico","Batterie","Inverter","Monitoraggio consumi","Soluzioni sostenibili"]',6),
('it','portali-web','Portali web','Esperienze web multilingua con servizi online.','Sviluppiamo siti aziendali, portali multilingua, aree clienti, e-commerce, moduli online, calendari e prenotazioni.','["Siti aziendali","Portali multilingua","Area clienti","E-commerce","Moduli online","Calendari e prenotazioni"]',7),
('it','programmi-app','Programmi e app','Software su misura per lavoro quotidiano e integrazioni.','Creiamo software Windows, applicazioni web, app mobile, database SQL Server, integrazioni gestionali e reportistica.','["Software Windows","Applicazioni web","App mobile","Database SQL Server","Integrazioni gestionali","Reportistica"]',8),
